    /// Input: one batch of KeyframeEntry (proxy pixels).
    type Input = Vec<KeyframeEntry>;
    /// Output: (id, enhanced_rgb, enh_w, enh_h, depth_f32, dw, dh) per keyframe.
    type Output = Vec<(String, Vec<u8>, usize, usize, Vec<f32>, usize, usize)>;

